WITH s AS (SELECT s.brand_name, SUM(s.product_gms) AS total_sales, SUM(s.shipped_cogs) AS shipped_cogs FROM shipped_raw s WHERE s.brand_name IS NOT NULL GROUP BY s.brand_name), c AS (SELECT c.brand_name, SUM(c.ncrc) AS total_ncrc FROM concession_raw c WHERE c.brand_name IS NOT NULL GROUP BY c.brand_name) SELECT s.brand_name, (s.total_sales - s.shipped_cogs - COALESCE(c.total_ncrc, 0)) AS net_margin, s.total_sales FROM s LEFT JOIN c ON c.brand_name = s.brand_name ORDER BY net_margin DESC NULLS LAST LIMIT 20;